import React, { useState, useEffect } from 'react';
import './AddTaskModal.css';

const SUBJECTS = [
  'Trí tuệ Nhân tạo',
  'Công nghệ Phần mềm',
  'Cơ sở Dữ liệu',
  'Mạng Máy tính',
  'Lập trình Web',
  'Hệ điều hành',
  'Cấu trúc Dữ liệu & Giải thuật',
  'Toán rời rạc',
  'Môn học khác',
];

const DEFAULT_FORM = {
  subject: 'Trí tuệ Nhân tạo',
  name: '',
  dueDate: '',
  instructions: '',
  notes: '',
};

export default function AddTaskModal({ open, onClose, onSave, editTask }) {
  const [form, setForm] = useState(DEFAULT_FORM);
  const isEditing = !!editTask;

  useEffect(() => {
    if (editTask) {
      setForm({
        subject: editTask.subject || '',
        name: editTask.name || '',
        dueDate: editTask.dueDate || '',
        instructions: editTask.instructions || '',
        notes: editTask.notes || '',
      });
    } else {
      setForm(DEFAULT_FORM);
    }
  }, [editTask, open]);

  if (!open) return null;

  function handleChange(e) {
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.name.trim()) return;
    onSave(form);
    onClose();
  }

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal-box">
        <div className="modal-header">
          <h2>{isEditing ? '✏️ Chỉnh sửa bài tập' : '➕ Thêm bài tập mới'}</h2>
          <button className="btn btn-icon btn-secondary" onClick={onClose}>✕</button>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="modal-body">
            {/* Subject */}
            <div className="form-group">
              <label className="form-label">Môn học *</label>
              <select
                className="form-select"
                name="subject"
                value={form.subject}
                onChange={handleChange}
              >
                {SUBJECTS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>

            {/* Task name */}
            <div className="form-group">
              <label className="form-label">Tên bài tập *</label>
              <input
                className="form-input"
                name="name"
                value={form.name}
                onChange={handleChange}
                placeholder="VD: Thiết kế ca ứng dụng Open Claw..."
                required
                autoFocus
              />
            </div>

            {/* Due date */}
            <div className="form-group">
              <label className="form-label">Hạn nộp</label>
              <input
                className="form-input"
                type="date"
                name="dueDate"
                value={form.dueDate}
                onChange={handleChange}
              />
            </div>

            {/* Instructions */}
            <div className="form-group">
              <label className="form-label">Hướng dẫn / Mô tả</label>
              <textarea
                className="form-textarea"
                name="instructions"
                value={form.instructions}
                onChange={handleChange}
                placeholder="Mô tả yêu cầu bài tập, tài liệu tham khảo..."
              />
            </div>

            {/* Notes */}
            <div className="form-group">
              <label className="form-label">Ghi chú cá nhân</label>
              <input
                className="form-input"
                name="notes"
                value={form.notes}
                onChange={handleChange}
                placeholder="VD: Đã hoàn thành 50%, cần xem video..."
              />
            </div>
          </div>

          <div className="modal-footer">
            <button type="button" className="btn btn-secondary" onClick={onClose}>Huỷ</button>
            <button type="submit" className="btn btn-primary">
              {isEditing ? '💾 Lưu thay đổi' : '✅ Thêm bài tập'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
